export const ConnectEmbeddedComponent: React.FC<ConnectEmbeddedComponentProps> = ({ componentName, _options = {} }) => {
  const { stripeConnectInstance } = useStripeConnect();
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
