    type,
    data,
    error: error?.message || error,
  };

  try {
    let currentLog = [];
    if (fs.existsSync(FAILED_LOG_PATH)) {
      const content = fs.readFileSync(FAILED_LOG_PATH, 'utf8');
      currentLog = JSON.parse(content);
    }
    currentLog.push(entry);
    fs.writeFileSync(FAILED_LOG_PATH, JSON.stringify(currentLog, null, 2));
    console.error(`🛡️ Evento fallido guardado en ${FAILED_LOG_PATH}`);
  } catch (fsErr) {
    console.error('CRITICAL: Failed to write to resilience log:', fsErr);
  }
}

/**
 * Logs data to a Google Sheet using Service Account authentication.
 */
export async function logToSheet(spreadsheetId: string | undefined, range: string, values: (string | number)[][]) {
  if (!spreadsheetId) {
    console.warn('Google Sheets Sync skipped: Spreadsheet ID not provided.');
    return null;
  }

  try {
    const auth = getAuth();
    const sheets = google.sheets({version: 'v4', auth});
    const response = await sheets.spreadsheets.values.append({
      spreadsheetId,
      range,
      valueInputOption: 'RAW',
      requestBody: {
        values,
      },
    });
    return response.data;
  } catch (error: any) {
    console.error('Error logging to Google Sheets:', error);
    await logFailedEvent('SHEETS_SYNC', { spreadsheetId, range, values }, error);
    throw error;
  }
}

/**
 * Crea un evento en Google Calendar.
 */
export async function createCalendarEvent(eventDetails: {
  summary: string;
  location?: string;
  description?: string;
  startTime: string;
  endTime: string;
}, calendarId = 'primary') {
  try {
    const auth = getAuth();
    const calendar = google.calendar({ version: 'v3', auth });

    const event = {
      summary: eventDetails.summary,
      location: eventDetails.location || '',
      description: eventDetails.description || '',
      start: {
        dateTime: eventDetails.startTime,
        timeZone: 'Europe/Madrid',
      },
      end: {
        dateTime: eventDetails.endTime,
        timeZone: 'Europe/Madrid',
      },
    };

    const response = await calendar.events.insert({
      calendarId,
      requestBody: event,
    });

    console.log('✅ Evento agendado en Calendar:', response.data.htmlLink);
    return response.data;
  } catch (error: any) {
    console.error('Error creating calendar event:', error);
    await logFailedEvent('CALENDAR_SYNC', { eventDetails, calendarId }, error);
    throw error;
  }
}

import Stripe from 'stripe';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY || '', {
  apiVersion: '2026-02-25.clover' as any,
});

export interface BookingOrder {
  id: string;
  customerName: string;
  email: string;
  phone: string;
  address: string;
  amount: number;
  currency: string;
  status: string;
  date: string;
  services: string[];
  whatsappSent?: boolean;
}

export async function getStripeOrders(limit = 50): Promise<BookingOrder[]> {
  try {
    const sessions = await stripe.checkout.sessions.list({
      limit,
      expand: ['data.line_items'],
    });

    return sessions.data
      .filter((session) => session.status === 'complete' && session.metadata?.customerName)
      .map((session) => ({
        id: session.id,
        customerName: session.metadata?.customerName || 'N/A',
        email: session.customer_details?.email || 'N/A',
        phone: session.metadata?.customerPhone || 'N/A',
        address: session.metadata?.customerAddress || 'N/A',
        amount: (session.amount_total || 0) / 100,
        currency: session.currency || 'eur',
        status: session.payment_status,
        date: new Date(session.created * 1000).toISOString(),
        services: session.metadata?.services ? JSON.parse(session.metadata.services) : [],
        whatsappSent: session.metadata?.whatsappSent === 'true',
      }));
  } catch (error) {
    console.error('Error fetching Stripe orders:', error);
    return [];
  }
}

export async function updateOrderMetadata(sessionId: string, metadata: Record<string, string>) {
  try {
    await stripe.checkout.sessions.update(sessionId, {
      metadata,
    });
    return { success: true };
  } catch (error) {
    console.error('Error updating metadata:', error);
    return { success: false, error };
  }
}
